const q = ($input.first().json.query) || {};
const dataset = (q.dataset || 'projects').toLowerCase();
const valid = ['projects','invoices','tokens','aftercare','contracts','llm_calls'];
if (!valid.includes(dataset)) return [{json:{valid:false,error:'dataset debe ser uno de: '+valid.join(', ')}}];
return [{json:{valid:true,dataset}}];

const rows = $input.first().json.rows || [];
const dataset = $('Pick Dataset').first().json.dataset;
if (rows.length === 0) return [{json:{csv:'dataset:'+dataset+',rows:0\n',filename:dataset+'_empty_'+new Date().toISOString().slice(0,10)+'.csv'}}];
const headers = Object.keys(rows[0]);
const esc = v => { if (v===null||v===undefined) return ''; const s=String(v); return /[",\n]/.test(s) ? '"'+s.replace(/"/g,'""')+'"' : s; };
const lines=[headers.join(',')];
for (const r of rows) lines.push(headers.map(h=>esc(r[h])).join(','));
return [{json:{csv:lines.join('\n'),filename:dataset+'_'+new Date().toISOString().slice(0,10)+'.csv',rows_count:rows.length}}];
